package speedwire

import (
	"encoding/hex"
	"testing"
)

func TestParsePacket(t *testing.T) {
	// Hex payload from documentation
	hexStr := ""
	data, err := hex.DecodeString(hexStr)
	if err != nil {
		t.Fatalf("Failed to decode hex string: %v", err)
	}

	packet, err := ParsePacket(data)
	if err != nil {
		t.Fatalf("Failed to parse packet: %v", err)
	}

	if packet.SusyID != 372 { // 0x0174 = 372
		t.Errorf("Expected SusyID 372, got %d", packet.SusyID)
	}
	if packet.SerialNumber != 3014003406 { // 0xb3a60ace = 3014003406
		t.Errorf("Expected SerialNumber 3014003406, got %d", packet.SerialNumber)
	}

	// Active Power Import: OBIS 0:1.4.0 (00 01 04 00) -> 0 W
	if packet.ActivePowerImport != 0 {
		t.Errorf("Expected ActivePowerImport 0, got %f", packet.ActivePowerImport)
	}

	// Active Energy Import: OBIS 0:1.8.0 (00 01 08 00) -> 0x5f815920 = 1602312480 Ws = 445086.8 Wh
	expectedEnergyImport := 1602312480.0 / 3600.0
	if packet.ActiveEnergyImport != expectedEnergyImport {
		t.Errorf("Expected ActiveEnergyImport %f, got %f", expectedEnergyImport, packet.ActiveEnergyImport)
	}

	// Active Power Export: OBIS 0:2.4.0 (00 02 04 00) -> 0x00001b55 = 7000 / 10 = 700 W
	// Wait, let's verify if 0x1b55 / 10.0 == 699.7. Let's calculate: 0x1b55 is 6997 in decimal. 6997 / 10.0 = 699.7 W
	if packet.ActivePowerExport != 699.7 {
		t.Errorf("Expected ActivePowerExport 699.7, got %f", packet.ActivePowerExport)
	}

	// Grid Frequency: OBIS 0:14.4.0 (00 0e 04 00) -> 0x0000c343 = 49987 / 1000 = 49.987 Hz
	// Wait, let's calculate: 0xc343 is 49987 in decimal. 49987 / 1000 = 49.987 Hz
	if packet.GridFrequency != 49.987 {
		t.Errorf("Expected GridFrequency 49.987, got %f", packet.GridFrequency)
	}
}
